package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithCommentMarker_lineBreakCharacter_exceptionThrown() {
        // Given
        Character commentMarker = '\n';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        try {
            Method method = CSVFormat.class.getDeclaredMethod("withCommentMarker", Character.class);
            method.setAccessible(true);
            method.invoke(csvFormat, commentMarker);
            fail("Expected IllegalArgumentException");
        } catch (InvocationTargetException e) {
            // Then
            assertTrue(e.getCause() instanceof IllegalArgumentException);
        } catch (NoSuchMethodException | IllegalAccessException e) {
            fail("Exception occurred while invoking private method");
        }
    }

    @Test
    public void testWithCommentMarker_validCharacter_noExceptionThrown() {
        // Given
        Character commentMarker = '#';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        try {
            Method method = CSVFormat.class.getDeclaredMethod("withCommentMarker", Character.class);
            method.setAccessible(true);
            CSVFormat result = (CSVFormat) method.invoke(csvFormat, commentMarker);

            // Then
            assertEquals(commentMarker, result.getCommentMarker());
        } catch (NoSuchMethodException | IllegalAccessException | InvocationTargetException e) {
            fail("Exception occurred while invoking private method");
        }
    }
}
